/**
 * Hook System Types
 *
 * Defines the event-driven hook system for the agent gateway.
 * Hooks respond to lifecycle events (messages, heartbeat, commands, startup).
 */
interface HookEvent {
    type: 'message' | 'heartbeat' | 'gateway' | 'command' | 'tool' | 'agent' | 'compaction';
    action: string;
    sessionKey: string;
    timestamp: Date;
    /** Push messages here to send back to the user */
    messages: string[];
    /** Event-specific data */
    context: Record<string, any>;
}
type HookHandler = (event: HookEvent) => Promise<void>;
interface Hook {
    name: string;
    description: string;
    events: string[];
    handler: HookHandler;
}
interface HookMetadata {
    name: string;
    description: string;
    events: string[];
    emoji?: string;
}

export type { Hook as H, HookEvent as a, HookHandler as b, HookMetadata as c };
